const publicDir = "./public/"

func handleFileUpload(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        http.Error(w, "Invalid request method", http.StatusBadRequest)
        return
    }

    fileHeader, err := r.FormFile("file")
    if err != nil || fileHeader == nil {
        log.Println(err)
        w.WriteHeader(http.StatusBadRequest)
        return
    }

    // Validate the uploaded file type
    if !isAllowedFileType(fileHeader.Filename) {
        log.Printf("Error: File type not allowed (%s)\n", fileHeader.Filename)
        http.Error(w, "Invalid file type", http.StatusForbidden)
        return
    }

    dst, err := os.OpenFile(publicDir+fileHeader.Filename, os.O_WRONLY|os.O_CREATE, 0666)
    if err != nil {
        log.Println(err)
        http.Error(w, "Error writing the uploaded file", http.StatusInternalServerError)
        return
    }
    defer dst.Close()

    _, err = io.Copy(dst, fileHeader)
    if err != nil {
        log.Println(err)
        http.Error(w, "Error saving the uploaded file", http.StatusInternalServerError)
        return
    }

    w.Header().Set("Content-Disposition", fmt.Sprintf(`attachment; filename="%s"`, fileHeader.Filename))
    w.WriteHeader(http.StatusCreated)

    // Return the URL to access the uploaded file
    filePath := publicDir + fileHeader.Filename
    log.Printf("File saved to: %s\n", filePath)
    http.Redirect(w, r, "/", http.StatusSeeOther)
}

func isAllowedFileType(filename string) bool {
    allowedExtensions := map[string]bool{
        "image/jpeg":   true,
        "image/png":    true,
        "application/pdf": true,
        "application/zip": true,
        "text/plain":  true,
    }

    extension := filepath.Ext(filename)
    if val, ok := allowedExtensions[extension]; ok {
        return val
    }
    return false
}

